require("dotenv").config();const fs=require("fs"),path=require("path");function loadIgnoredCollections(){try{const filePath=path.join(__dirname,"ignored-collections.txt");if(!fs.existsSync(filePath))return console.log("ℹ️ No ignored-collections.txt file found"),[];const collections=fs.readFileSync(filePath,"utf-8").split("\n").map((line=>line.trim())).filter((line=>line.length>0&&!line.startsWith("#"))).map((slug=>slug.toLowerCase()));return collections.length>0&&console.log(`🚫 Loaded ${collections.length} ignored collection(s):`,collections),collections}catch(error){return console.error("❌ Error loading ignored collections:",error.message),[]}}module.exports={discord:{botToken:process.env.DISCORD_BOT_TOKEN,channelId:process.env.DISCORD_CHANNEL_ID,nftsRoleId:process.env.DISCORD_NFTS_ROLE_ID},opensea:{apiKey:process.env.OPENSEA_API_KEY||"REMOVED_ROTATED_KEY"},scanInterval:process.env.SCAN_INTERVAL?parseInt(process.env.SCAN_INTERVAL):6e4,csvFile:"wallets.csv",ignoredCollections:loadIgnoredCollections()};